head.script:
    //자회사물류/오더/통합매출입/확정전 매입전표 조회 및 삭제
    //테스트 로그인 330042/1111
    //조회 : 회사코드 - 028, 정산부서 01383, 전표일자 20240531

    scwin.vLoginCoCd = $c.gus.cfIsNull($c.data.getMemInfo("coCd"))?'': $c.data.getMemInfo("coCd"); // 소속 자회사  
	scwin.vLoginCoClsCd = $c.gus.cfIsNull($c.data.getMemInfo("coClsCd"))?'': $c.data.getMemInfo("coClsCd"); //회계_회사구분('CO035' : 0:동부 EXPRESS)
	scwin.vUserHomeClsCd= $c.data.getMemInfo("userHomeClsCd");        // 사용자소속구분코드 

	scwin.vCoCd = $c.gus.cfIsNull($c.data.getMemInfo("coCd"))?'': $c.data.getMemInfo("coCd"); // 소속 자회사
	scwin.vCoClsCd = $c.gus.cfIsNull($c.data.getMemInfo("coClsCd"))?'': $c.data.getMemInfo("coClsCd"); //회계_회사구분('CO035' : 0:동부 EXPRESS)

    scwin.privAdmin = $c.data.getMemInfo("privAdmin"); //ADMIN 권한 ADMIN 권한 CHK : 'T' : ADMIN , 'F': ADMIN 아님
    scwin.empNo = $c.data.getMemInfo("userId"); //사용자 아이디

    scwin.vQryStDt = $c.date.getServerDateTime("yyyyMM")+"01";
    scwin.vQryEndDt = $c.date.getServerDateTime("yyyyMMdd");// 현재일자를 구한
    scwin.txtCoClsCd = '';

    scwin.onpageload = function() {

    };

    scwin.onUdcCompleted = function() {
        scwin.f_OnLoad();
    };

	//-------------------------------------------------------------------------
	// 화면로딩시
	//-------------------------------------------------------------------------
	scwin.f_OnLoad = function () {
		//f_SetDataHeader();
		scwin.f_SetDefaultData();
		$c.gus.cfDisableBtnOnly([btn_save]);

		scwin.f_setCompanyInfo();
	};

	//-------------------------------------------------------------------------
	// 자회사 회계 시스템 추가에 따른 설정 
	//-------------------------------------------------------------------------
	scwin.f_setCompanyInfo = function ()
	{   
		ed_coCd.setValue(scwin.vLoginCoCd);
		scwin.f_PopUpCompanyInfo('T'); 

    	//$c.gus.cfDisableObjects([ed_coCd,ed_coNm,img_company  ]);
    	$c.gus.cfDisableObjects([udc_coCd]);
 	};

//-------------------------------------------------------------------------
  // 회사 입력 팝업 
  //-------------------------------------------------------------------------
	scwin.f_PopUpCompanyInfo = function (pWinCloseTF )
	{
	    //var rtnList = cfCommonPopUp("retrieveDongbuGroupCompanyInfo"
        udc_coCd.setSelectId("retrieveDongbuGroupCompanyInfo");
	    var rtnList = udc_coCd.cfCommonPopUp(scwin.udc_coCdCallback
										,ed_coCd.getValue(), ed_coNm.getValue()
										,pWinCloseTF,null,null,null,null
										,null,null,null,null,null);
	 };

	 scwin.f_initObj = function () {
	  	$c.gus.cfInitObjects([ed_pchsDeptCd,ed_pchsDeptNm]); // 부서코드 
	  	$c.gus.cfInitObjects([ed_pchsClntNo,ed_pchsClntNm]); //  거래처 코드 
	  };

	//-------------------------------------------------------------------------
	// Default Data Setting
	//-------------------------------------------------------------------------
	scwin.f_SetDefaultData = function () {
		ica_slipDtSt.setValue(scwin.vQryStDt);    // 전표일자시작
		ica_slipDtEnd.setValue(scwin.vQryEndDt);  // 전표일자종료
		acb_dcsnClsCd.setValue("");               // 확정구분

		//$c.gus.cfSetIMEModeActiveObjects([ed_pchsDeptNm, ed_admitPicNm, ed_pchsClntNm]);  // IME 한글입력

		ed_pchsDeptCd.focus();
	};

	//-----------------------------------------------    vmnbcvnhgfc--------------------------
	// 매입거래명세서 조회
	//-------------------------------------------------------------------------
	scwin.f_RetrievePurchaseEvidenceList = async function () {
		// 검색조건 필수 입력 체크, 동일 날짜 포함 여부 체크
	  	if (! await $c.gus.cfValidate([ed_pchsDeptCd, ica_slipDtSt, ica_slipDtEnd])) {
	  		return;
		}

		if (!$c.gus.cfIsAfterDate(ica_slipDtSt.getValue(), ica_slipDtEnd.getValue())) {
			await $c.gus.cfAlertMsg("조회 시작일자는 종료일자 보다 이전 날짜 이어야 합니다.");
			ica_slipDtSt.focus();
			return;
		}

        $c.sbm.execute(sbm_purchaseCertiQueryConditionDTO);
		//tr_purchaseCertiQueryConditionDTO.post();
	};

	//-------------------------------------------------------------------------
	// 전표 삭제
	//-------------------------------------------------------------------------
	scwin.f_CancelSlip = async function () {
		// Data 변경 여부 조회
		//if (!ds_purchaseEvidenceList.IsUpdated) {
		if (ds_purchaseEvidenceList.getModifiedJSON().length == 0) {
			await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["목록"]);  // 선택된 @이(가) 없습니다.
			return;
		}

		if (await $c.win.confirm("전표를 삭제하시겠습니까?")) {
            $c.sbm.execute(sbm_cancelSlip);
			//tr_cancelSlip.Post();
		}
	};

	//-------------------------------------------------------------------------
	// 엑셀 다운로드
  	//-------------------------------------------------------------------------
    scwin.f_RunExcel = async function (value) {
        var count = ds_purchaseEvidenceList.getRowCount();
        if (!(count > 0)) {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_002);  // 조회결과가 존재하지 않습니다.
            return;
        } else {
            // {"fileName":"매입전표 조회 및 삭제.xlsx","type":"4+8+16"}
            const infoArr = [{
                rowIndex    : 0
                , colIndex    : 0
                , rowSpan     : 1
                , colSpan     : gr_purchaseEvidenceList.getTotalCol()
                , text        : "매입전표 조회 및 삭제"
                , textAlign   : "center"
                // , fontSize    : "12pt"
                , fontName    : "돋움체"
                , color       : "black"
                , fontWeight  : ""
                , drawBorder  : "false"
                , borderColor : ""
                , borderWidth : ""
                , wordWrap    : "true"
                , bgColor     : "#ffffff"
            }];
            const options = {
                fileName : "매입전표 조회 및 삭제.xlsx", //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
                sheetName: "매입전표 조회 및 삭제",
                type : "1",
                startRowIndex: 2,
                // removeColumns: "0,21",
                // hiddenVisible : true,
                // useSubTotal :"true", 
                // useSubTotalData  : "true",
                // oddRowBackgroundColor  : "",                        // excel파일에서 그리드 body의 홀수줄의 배경색
                // evenRowBackgroundColor : "#F5FFF5"                  // excel파일에서 그리드 body의 짝수줄의 배경색
            };
            $c.data.downloadGridViewExcel(gr_purchaseEvidenceList, options, infoArr);
        }
	};

	//-------------------------------------------------------------------------
	// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
	//-------------------------------------------------------------------------
	scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
	  	// 선언부
		var rtnList  = new Array();  // 공통POP-UP -> 요청화면 
		var qryYear = scwin.vQryEndDt.substring(0,4);
		//var qryYear = <%=DDate.getDate().substring(0,4)%>;
		//var qryYear = scwin.vQryEndDt;

		switch (disGubun) {

	  		case 1:
				// 정산부서 팝업
// 				rtnList = cfCommonPopUp('retrieveLobranInfo',pCode.trim(),pName,pClose,null,null,null,null,null,null,null,null,null,null,pAllSearch,null);

// 				cfSetReturnValue(rtnList, ed_pchsDeptCd, ed_pchsDeptNm);  // 정산부서코드, 정산부서명
// 				break;

				var param = ","+ed_coCd.getValue()+","+scwin.txtCoClsCd+",0";

		 		//rtnList = udc_pchsDeptCd.cfCommonPopUp('retrieveAcctDeptCdInfo6',ed_pchsDeptCd.getValue().trim(),ed_pchsDeptNm.getValue(),'T',null,null,null,null,param,null,null,null,null,null,null,null,null,null,qryYear); 
                udc_pchsDeptCd.setSelectId("retrieveAcctDeptCdInfo6");
		 		rtnList = udc_pchsDeptCd.cfCommonPopUp(scwin.udc_pchsDeptCdCallback,ed_pchsDeptCd.getValue().trim(),ed_pchsDeptNm.getValue(),'T',null,null,null,null,param,null,null,null,null,null,null,null,null,null,qryYear); 
				//scwin.f_resultPopEd(ed_pchsDeptCd,ed_pchsDeptNm,rtnList);
				break;

	  		case 2:
				// 작성자 팝업
				var param=",,,"+ed_coCd.getValue();
				//rtnList = cfCommonPopUp('retrieveEmpInfo3',pCode.trim(),pName,pClose,null,null,null,null,param,null,null,null,null,null,pAllSearch,null);	  				  			

                udc_admitPic.setSelectId("retrieveEmpInfo3");
				rtnList = udc_admitPic.cfCommonPopUp(scwin.udc_admitPicCallback,pCode.trim(),pName,pClose,null,null,null,null,param,null,null,null,null,null,pAllSearch,null);	  				  			
				//cfSetReturnValue(rtnList, ed_admitPic, ed_admitPicNm);  // 사번, 성명
				break;

			case 3:
	  			// 매입거래처 팝업
// 				rtnList = cfCommonPopUp('retrieveClntList',pCode.trim(),pName,pClose,null,null,null,null,null,null,null,null,null,null,pAllSearch,null);

// 				cfSetReturnValue(rtnList, ed_pchsClntNo, ed_pchsClntNm);  // 매입거래처코드, 매입거래처명
// 				break;

				var param=",,,"+ed_coCd.getValue();

		    	//rtnList = cfCommonPopUp('retrieveClntList2',ed_pchsClntNo.getValue().trim(),ed_pchsClntNm.getValue(),'T',null,null,null,null,param,null,null,null,null);

                udc_pchsClntNo.setSelectId("retrieveClntList2");
		    	rtnList = udc_pchsClntNo.cfCommonPopUp(scwin.udc_pchsClntNoCallback,ed_pchsClntNo.getValue().trim(),ed_pchsClntNm.getValue(),'T',null,null,null,null,param,null,null,null,null); 
				//scwin.f_resultPopEd(ed_pchsClntNo,ed_pchsClntNm,rtnList);
				break;

	  		default:
	  			break;
		}
	};

	//-------------------------------------------------------------------------
	// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
	//-------------------------------------------------------------------------
	scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
		// 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
		if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
			return;

		// 짝이 되는 오브젝트의 값 제거
		$c.gus.cfClearPairObj(pairObj);

		// 검색어 세팅
		var pVal = $c.gus.cfGetValue(inObj);

		// inObj가 코드 필드일 경우 팝업
		if (isCode == null || isCode == true)
			scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
		// inObj가 코드명 필드일 경우 팝업
		else
			scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
	};

    scwin.udc_coCdCallback = function (rtnList) {
        // SET	 
        if(rtnList != null ) { 
        if (rtnList[0] == "N/A") return; 

        if(ed_coCd.hidVal != rtnList[0] )
            scwin.f_initObj();

            ed_coCd.setValue(rtnList[0]);	// 코드
            ed_coNm.setValue(rtnList[5]); // 회사명 
            ed_coCd.hidVal = rtnList[0];  // 히든값
            scwin.txtCoClsCd = rtnList[1];	// 회사구분    
        }else{
            ed_coCd.setValue("");
            ed_coNm.setValue("");
            ed_coCd.hidVal = ""; 
            scwin.txtCoClsCd = "";
        }

        /*
        if(scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU)  {  	// 자회사 회계 시스템 
            isSubCompany = true;
        }else{
            isSubCompany = false;
        }
        */
    };

    scwin.udc_pchsDeptCdCallback = function (rtnList) {
        scwin.f_resultPopEd(ed_pchsDeptCd,ed_pchsDeptNm,rtnList);
    };

    scwin.udc_admitPicCallback = function (rtnList) {
        $c.gus.cfSetReturnValue(rtnList, ed_admitPic, ed_admitPicNm);  // 사번, 성명
    };

    scwin.udc_pchsClntNoCallback= function (rtnList) {
        scwin.f_resultPopEd(ed_pchsClntNo,ed_pchsClntNm,rtnList);
    };

	//-------------------------------------------------------------------------
	// 검색영역 Field Clear함.
	//-------------------------------------------------------------------------
	scwin.f_InitObjects = function () {
		$c.gus.cfInitObjects(tb_mainData);
		scwin.f_SetDefaultData();
	};


	//-------------------------------------------------------------------------
	// 조회 귀속부서코드팝업
	//-------------------------------------------------------------------------
	scwin.f_deptPopUp = function (deptCd, deptNm) {
	var param =  scwin.vQryEndDt;

	if(scwin.vCoClsCd > ACConstants.CO_CLS_CD_DONGBU)  {  	// 자회사 회계 시스템
		param = param+","+scwin.vCoCd+","+scwin.vCoClsCd;
	} 
	var paramArray = new Object();
	paramArray.pSelectID = "retrieveAcctDeptCdInfo6";
	paramArray.pCode = deptCd;
	paramArray.pName = deptNm;
	paramArray.pWhere = param;
	var rtnList = scwin.f_PopUp2(paramArray);
	};

	//-------------------------------------------------------------------------
	// 팝업
	//-------------------------------------------------------------------------
	scwin.f_PopUp2 = function (paramArray) {
		var codeObj = paramArray.pCode;
		var nameObj = paramArray.pName;

		//rtnList = udc_pchsDeptCd.cfCommonPopUp(paramArray.pSelectID, cfGetValue(codeObj), ""

        udc_pchsDeptCd.setSelectId(paramArray.pSelectID);
		rtnList = udc_pchsDeptCd.cfCommonPopUp(scwin.udc_pchsDeptCdCallback
                               , $c.gus.cfGetValue(codeObj), ""
							   ,scwin.f_EventCheck(), paramArray.pDispCnt
							   ,paramArray.pTitle, paramArray.pWidth
							   ,paramArray.pHidden, paramArray.pWhere
							   ,paramArray.pW, paramArray.pH
							   ,paramArray.pTop, paramArray.pLeft
							   ,paramArray.pExistTF, paramArray.pAllSearchTF
							   ,paramArray.pWtitleSearch)
/*
		if (rtnList != null ) {
	    	if (rtnList[0] != "N/A") {
	    		$c.gus.cfSetValue(codeObj,rtnList[0]);
				codeObj.hidVal = rtnList[0];
				$c.gus.cfSetValue(nameObj,rtnList[1]);
			}
	    } else {
			$c.gus.cfSetValue(codeObj,"");
			codeObj.hidVal = "";
			$c.gus.cfSetValue(nameObj,"");
	    }
*/
		return rtnList;
	};

	//-------------------------------------------------------------------------
	// 팝업 이벤트에 따라 팝업창의 자동닫기 여부를 반환
	//-------------------------------------------------------------------------
	scwin.f_EventCheck = function () {
