scwin.sbm_purchaseCertiQueryConditionDTO_submitdone = function (e) {
/*
    //gr_purchaseEvidenceList.ColumnProp('chk','HeadCheck') = "false";

    // 총 조회건수 표시
    cfShowTotalRows(totalRows, rowCnt);

    if (rowCnt == 0) {
        cfDisableBtnOnly([btn_save]);
        cfAlertMsg(MSG_CM_ERR_003);  // 해당되는 자료가 존재하지 않습니다
    } else {
        cfEnableBtnOnly([btn_save]);
    }
*/

    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    var rowCnt = ds_purchaseEvidenceList.getRowCount();
    tbx_totalRows.setValue(rowCnt);
    if (rowCnt == 0) {
        $c.gus.cfDisableBtn([btn_save]);
        $c.gus.cfAlertMsg(MSG_CM_ERR_003);  // 해당되는 자료가 존재하지 않습니다
    } else {
        $c.gus.cfEnableBtnOnly([btn_save]);
    }
};


scwin.gr_purchaseEvidenceList_oncellclick = async function (rowIndex, columnIndex, columnId) {
    if (columnId == "chk") {
        // 확정구분이 계산서작성(3)인 경우 전표 삭제
        for (var i=0; i<ds_purchaseEvidenceList.getRowCount(); i++) {
            if (ds_purchaseEvidenceList.getCellData(i, "chk") == "T" && ds_purchaseEvidenceList.getCellData(i, "dcsnClsCd") != "3") {
                ds_purchaseEvidenceList.setCellData(i, "chk", "F");
                await $c.gus.cfAlertMsg("확정구분이 계산서작성인 경우만 가능합니다.");
                return;
            }
        }

        var cnt = 0;
        for (var i=0; i<ds_purchaseEvidenceList.getRowCount(); i++) {
            if (ds_purchaseEvidenceList.getCellData(i, "chk") == "T") {
                cnt++;
            }
        }

        if (cnt > 1) {
            ds_purchaseEvidenceList.setCellData(ds_purchaseEvidenceList.getRowPosition(), "chk", "F");
            await $c.gus.cfAlertMsg(MSG_CM_WRN_007, ["1건"]);  // @을(를) 선택하십시오.
            return;
        }
    }
};

scwin.sbm_cancelSlip_submitdone = async function (e) {
        if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail

		await $c.gus.cfAlertMsg(MSG_CM_INF_001);	 // 성공적으로 저장하였습니다
		scwin.f_RetrievePurchaseEvidenceList();
};
